-- Preeku stocks seed (2265 stocks)
-- Run on EC2: psql -U preeku -d preekudb < /tmp/stocks_seed.sql

ON CONFLICT (symbol) DO UPDATE SET
  name = EXCLUDED.name, exchange = EXCLUDED.exchange, sector = EXCLUDED.sector,
  current_price = EXCLUDED.current_price, previous_close = EXCLUDED.previous_close,
  high = EXCLUDED.high, low = EXCLUDED.low, volume = EXCLUDED.volume,
  market_cap = EXCLUDED.market_cap, updated_at = NOW();
